llm_fixed_code:
always @(posedge clk) begin
    case(r_State)
        2'h0: begin
            if(i_Read_Request | i_Write_Request) begin  
                r_Cmd <= CMD_ACTIVE;  
                o_Bank_Address <= w_Address[19];  
                o_Address_10 <= w_Address[18:8]; 
                o_Data_Mask <= 2'b11;
                r_State <= 2'h1;
            end
            else begin
                r_Cmd <= CMD_NOP;  
                o_Bank_Address <= 0;
                o_Address_10 <= 0;
                o_Data_Mask <= 2'b11;
                // Ensure we do not drop o_Write_Grant prematurely
                if (o_Write_Grant) begin
                    r_State <= 2'h0;
                end
            end
        end
    endcase 
end

always @(posedge clk) begin
    case(r_State)
        2'h0: begin
            if(i_Read_Request | i_Write_Request) begin  
                r_Cmd <= CMD_ACTIVE;  
                o_Bank_Address <= w_Address[19];  
                o_Address_10 <= w_Address[18:8]; 
                o_Data_Mask <= 2'b11;
                if (w_Write_Now) begin
                    r_State <= 2'h1; // Transition to ACCESS state for write
                end else begin
                    r_State <= 2'h2; // Transition to PRECHARGE state for read
                end
            end

            else begin
                r_Cmd <= CMD_NOP;  
                o_Bank_Address <= 0;
                o_Address_10 <= 0;
                o_Data_Mask <= 2'b11;
                r_State <= 2'h0;
            end
        end

        // Other states remain unchanged for brevity
    endcase 
end

if (round_ctr_reg == SHA1_ROUNDS)
  begin
    sha1_ctrl_new = CTRL_DONE;
    sha1_ctrl_we  = 1'h1;
  end

if ((round_ctr_reg >= 20) && (round_ctr_reg <= 39))
  begin
    k = 32'h6ed9eba1;
    f = b_reg ^ c_reg ^ d_reg; // Corrected line to ensure proper computation of 'f'
  end

always @ (posedge clk)
  if (rst) begin
    lgnt0 <= 0;
    lgnt1 <= 0;
    lgnt2 <= 0;
    lgnt3 <= 0;
  end else begin
    lgnt0 <= (~lcomreq & ~lmask1 & ~lmask0 & ~req3 & ~req2 & ~req1 & req0) | (lcomreq & lgnt0);
    lgnt1 <= (~lcomreq & ~lmask1 & ~lmask0 &  req1) | (lcomreq & lgnt1);
    lgnt2 <= (~lcomreq & ~lmask1 & ~lmask0 &  req2 & ~req1) | (lcomreq & lgnt2);
    lgnt3 <= (~lcomreq & ~lmask1 & ~lmask0 & req3 & ~req2 & ~req1) | (lcomreq & lgnt3);
  end

always @ (posedge clk)
if( rst )
begin
  lmask1 <= 0;
  lmask0 <= 0;
end
else if(mask_enable) // Ensure mask_enable is correctly driven and updated
begin
  lmask1 <= lgnt[1];
  lmask0 <= lgnt[0];
end
else
